class Solution:
    def reformatNumber(self, number: str) -> str:
        number = number.replace(" ", "").replace("-", "")
        if len(number) <= 4:
            return number
        blocks = []
        for i in range(0, len(number), 3):
            blocks.append(number[i:i+3])
        if len(number) % 3 != 0:
            blocks[-1] = number[-3:]
        if len(blocks) > 2:
            blocks = blocks[:-1] + ["-" + "-".join(blocks[-1:])]
        return "-".join(blocks)
